INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (1, 1, 1, 'Grip the barbell with your hands slightly wider than shoulder-width apart, palms facing your feet, and lift it off the rack, holding it straight over your chest with your arms fully extended.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (2, 1, 2, 'Slowly lower the barbell down to your chest while keeping your elbows at a 90-degree angle.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (3, 1, 3, 'Once the barbell touches your chest, push it back up to the starting position while keeping your back flat on the bench.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (4, 1, 4, 'Repeat this process for the desired number of repetitions, always maintaining control of the barbell and ensuring your form is correct.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (5, 2, 1, 'Sit down on the bench with your feet flat on the floor and grip the barbell with your palms facing towards you, ensuring that your hands are shoulder-width apart.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (6, 2, 2, 'Lift the barbell off the rack and hold it directly above your chest with your arms fully extended, this is your starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (7, 2, 3, 'Slowly lower the barbell towards your chest while keeping your elbows close to your body, pause for a moment when the barbell is just an inch away from your chest.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (8, 2, 4, 'Push the barbell back to the starting position while exhaling, fully extending your arms but not locking your elbows. Repeat the exercise for the desired number of repetitions.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (9, 3, 1, 'Lower your body towards the ground, keeping your back straight and your core engaged, until your chest is just above the ground.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (10, 3, 2, 'Press your body back up, extending your arms fully but not locking your elbows, while maintaining the diamond shape with your hands.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (11, 3, 3, 'Ensure to keep your body in a straight line from your head to your heels throughout the movement.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (12, 3, 4, 'Repeat this process for the desired number of repetitions, ensuring to keep your form correct throughout.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (13, 4, 1, 'With a dumbbell in one hand, raise your arm until it is fully extended above you, keeping your palm facing inward in a hammer grip (thumb up).', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (14, 4, 2, 'Slowly lower the dumbbell towards your shoulder, bending your elbow and keeping the rest of your body still, until your arm forms a 90-degree angle.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (15, 4, 3, 'Push the dumbbell back up to the starting position, fully extending your arm but not locking your elbow, while exhaling and engaging your chest muscles.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (16, 4, 4, 'Repeat the movement for your desired amount of repetitions, then switch to the other arm and repeat the process.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (17, 5, 1, 'Hold a dumbbell in one hand with a neutral grip (palms facing inward), at chest level, fully extending your arm upward to prepare for the press.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (18, 5, 2, 'Slowly lower the dumbbell towards your chest, keeping your elbow close to your body and ensuring that your wrist stays straight.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (19, 5, 3, 'Once the dumbbell is near your chest, push it back up to the starting position, fully extending your arm but not locking your elbow.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (20, 5, 4, 'Repeat this movement for the desired number of repetitions before switching to the other arm.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (21, 6, 1, 'Bend your elbows to lower the dumbbell behind your head, keeping your upper arms stationary and close to your head.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (22, 6, 2, 'Make sure your elbows are at about a 90-degree angle at the bottom of the movement.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (23, 6, 3, 'Push the dumbbell back up to the starting position using your triceps to lift the weight.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (24, 6, 4, 'Repeat this exercise for the desired amount of repetitions, ensuring you maintain your form throughout.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (25, 7, 1, 'Keeping your back pressed firmly against the bench and your feet flat on the floor, push the dumbbells upward until your arms are fully extended, but do not lock your elbows.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (26, 7, 2, 'Hold this position for a moment, making sure to keep your core engaged and your shoulders down to avoid straining your neck.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (27, 7, 3, 'Slowly lower the dumbbells back to the starting position at shoulder level, ensuring that you control the movement rather than letting the weights drop.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (28, 7, 4, 'Repeat this movement for your desired number of repetitions, maintaining proper form throughout.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (29, 8, 1, 'Raise the dumbbells to shoulder height, then rotate your palms so they are facing forward.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (30, 8, 2, 'Push the dumbbells upward until your arms are fully extended above your head.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (31, 8, 3, 'Slowly lower the dumbbells back to shoulder height while rotating your palms to face your body again.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (32, 8, 4, 'This completes one rep; repeat the process for your desired number of repetitions.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (33, 9, 1, 'Bend your knees slightly and using your whole body, lift the dumbbells up to your shoulders in a swift, clean motion, rotating your wrists so that your palms face forward.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (34, 9, 2, 'Once the dumbbells are at shoulder height, press them upward until your arms are fully extended, keeping your core engaged and your back straight.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (35, 9, 3, 'Hold the position for a second, then slowly lower the dumbbells back to your shoulders.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (36, 9, 4, 'Finally, bring the dumbbells back down to your sides in a controlled motion, completing one rep. Repeat this for the desired number of repetitions.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (37, 10, 1, 'Push up through your hands to lift your hips off the floor, keeping your chest up and your back straight.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (38, 10, 2, 'Slowly lower your body by bending your elbows until they are at about a 90-degree angle, then push your body back up to the starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (39, 10, 3, 'Make sure to keep your hips close to your hands during the movement to target the triceps effectively.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (40, 10, 4, 'Repeat this motion for the desired number of repetitions, ensuring to maintain proper form throughout the exercise.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (41, 11, 1, 'Slowly bend your knees and lower your body as if you''re about to sit on a chair, keeping your chest upright and your knees over your toes.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (42, 11, 2, 'Continue lowering yourself until your thighs are parallel or almost parallel to the floor, this is the squat position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (43, 11, 3, 'Pause for a moment in the squat position, then push through your heels to rise back up to the starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (44, 11, 4, 'Repeat this movement for the desired number of repetitions while maintaining proper form.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (45, 12, 1, 'Engage your core and keep your chest up, then start to lower your body into a squat position by bending your knees and pushing your hips back.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (46, 12, 2, 'Continue lowering yourself until your hips are below your knees, making sure your elbows are inside your knees at the bottom of the squat.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (47, 12, 3, 'Pause for a moment at the bottom of the squat, then push through your heels to stand back up to the starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (48, 12, 4, 'Repeat this movement for the desired number of repetitions, making sure to maintain proper form throughout the exercise.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (49, 13, 1, 'Lower your body into a squat position and place your hands on the floor in front of you.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (50, 13, 2, 'Kick your feet back quickly, extending your legs behind you and landing in a push-up position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (51, 13, 3, 'Quickly bring your feet back towards your hands, returning to the squat position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (52, 13, 4, 'Stand up straight again, pushing through your heels and extending your hips and knees, completing one squat thrust. Repeat this sequence for the desired number of repetitions.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (53, 14, 1, 'Begin the movement by pushing your hips back and bending your knees, while simultaneously rising onto the balls of your feet. Keep your back straight and your chest up.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (54, 14, 2, 'Lower your body as far as you can, ideally until your thighs are parallel to the floor, while keeping your heels off the ground. Your body should form a straight line from your head to your knees.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (55, 14, 3, 'Hold the bottom position for a second, then push through the balls of your feet to rise back up to the starting position, keeping your body straight and your core engaged throughout the movement.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (56, 14, 4, 'Repeat the exercise for the desired number of reps. Remember to keep a slow and controlled movement pace throughout the exercise to maximize muscle engagement.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (57, 15, 1, 'Keep your upper body straight, with your shoulders back and relaxed and chin up, then slowly lower your body as far as you can by bending your knees. Your right knee should be directly above your ankle, and your left knee should not touch the floor.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (58, 15, 2, 'Hold this position for a few seconds, making sure to keep your core engaged and your hips square.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (59, 15, 3, 'Push back up to the starting position through your right heel, keeping your weight balanced evenly, not leaning forward or backward.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (60, 15, 4, 'Repeat the movement with your left leg stepping forward. Remember to do an equal number of repetitions on each side to ensure balanced strength development.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (61, 16, 1, 'Lower your body into a squat position by bending your knees and pushing your hips back, keeping your chest upright and your knees over your toes.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (62, 16, 2, 'Once you''re in a deep squat, push through your heels to jump up explosively, swinging the dumbbells upward to shoulder height as you rise.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (63, 16, 3, 'As you land, control your body back into the squat position, absorbing the impact with your legs, and immediately prepare for the next jump.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (64, 16, 4, 'Repeat this process for the desired number of repetitions, maintaining a smooth and controlled rhythm throughout the exercise.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (65, 17, 1, 'Lower your body by bending your knees and hips, keeping your back straight and your chest upright, as if you''re trying to sit between your legs.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (66, 17, 2, 'Continue to lower yourself until your thighs are parallel to the floor, ensuring your knees are directly above your ankles.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (67, 17, 3, 'Pause for a moment at the bottom of the squat, keeping your core engaged.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (68, 17, 4, 'Push through your heels to return to the starting position, straightening your legs and squeezing your glutes at the top of the movement.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (69, 18, 1, 'Keep your chest up and your core engaged as you lower your body down into a lunge position, bending both knees to about a 90-degree angle, while ensuring your right knee doesn''t go past your right foot.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (70, 18, 2, 'Push through your right heel to lift your body back up to the starting position, keeping your left foot on the bench or box.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (71, 18, 3, 'Repeat this movement for the desired number of repetitions, then switch legs and perform the same steps.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (72, 18, 4, 'Remember to maintain good posture throughout the exercise, keeping your back straight and your gaze forward.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (73, 19, 1, 'Begin the exercise by performing a regular squat, bending your knees and pushing your hips back as if you''re about to sit on a chair.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (74, 19, 2, 'Once you reach the lowest point of your squat, use your feet to explode upwards, jumping as high as you can.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (75, 19, 3, 'As you land, control your body to smoothly transition back into the squat position, absorbing the impact with your legs.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (76, 19, 4, 'Repeat this process for your desired number of repetitions, ensuring to maintain proper form throughout the exercise.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (77, 20, 1, 'Shift your weight onto your left leg, and raise your right leg off the floor, extending it forward slightly.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (78, 20, 2, 'Slowly bend your left knee, lowering your body as far as you can without losing balance, ensure your knee doesn''t go past your toes.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (79, 20, 3, 'Pause for a moment at the bottom of the squat, then push through your left foot to straighten your leg and return to the starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (80, 20, 4, 'Repeat this movement for the desired number of reps, then switch legs and do the same on the other side.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (81, 21, 1, 'Keep your back straight and your shoulders back as you begin to bend at the hips, pushing them back while you lower the barbell along the front of your legs.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (82, 21, 2, 'Continue lowering the barbell until it reaches mid-shin level, or until you feel a stretch in your hamstrings, making sure to keep the barbell close to your body throughout the movement.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (83, 21, 3, 'After reaching this position, pause for a moment, and then slowly reverse the movement by driving your hips forward and standing back up to the starting position, squeezing your glutes at the top.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (84, 21, 4, 'Remember to keep your core engaged and your back straight throughout the entire exercise to avoid injury.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (85, 22, 1, 'Keeping your back straight and your head up, lower your torso by bending at the hips until it''s nearly parallel with the floor.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (86, 22, 2, 'As you lower your torso, keep the dumbbells as close as possible to your body and allow them to lower towards your feet.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (87, 22, 3, 'Pause for a moment at the bottom of the movement, then reverse the motion by extending through your hips until you''re standing upright again.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (88, 22, 4, 'Repeat this movement for the desired number of repetitions, ensuring to maintain a straight back and controlled movements throughout the exercise.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (89, 23, 1, 'Shift your weight onto your right foot, then slowly lift your left leg behind you while extending your right arm in front of you, keeping both parallel to the floor.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (90, 23, 2, 'Keep your back straight and your right knee slightly bent, as you hinge at the hips to lower your torso towards the ground, maintaining balance.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (91, 23, 3, 'Pause for a moment when your body forms a T shape, then slowly return to the starting position, keeping your movements controlled and your core engaged.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (92, 23, 4, 'Repeat the exercise for the desired number of repetitions, then switch to the other leg and arm and perform the same steps.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (93, 24, 1, 'Keeping your legs straight or with a slight bend in the knees, slowly bend at the hips, lowering the dumbbells towards the floor.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (94, 24, 2, 'Lower the dumbbells until you feel a stretch in your hamstrings, ensuring that your back is straight and your chest is up.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (95, 24, 3, 'Pause briefly at the bottom of the movement, then push your hips forward and slowly lift your torso back to the starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (96, 24, 4, 'Repeat the movement for the desired number of repetitions, ensuring to maintain proper form throughout the exercise.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (97, 25, 1, 'Slowly bend forward at the hips, keeping your back straight and extending your free leg behind you for balance.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (98, 25, 2, 'Continue to bend forward until your torso is parallel to the floor, or as far as your flexibility allows, making sure to keep your standing leg slightly bent.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (99, 25, 3, 'Pause for a moment at the bottom of the movement, then slowly return to the starting position, maintaining balance and control throughout the movement.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (100, 25, 4, 'Repeat the exercise for your desired number of repetitions, then switch legs and perform the same number of repetitions with the other leg.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (101, 26, 1, 'Set your desired workout settings on the machine''s console, such as time, resistance level, and incline, if available.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (102, 26, 2, 'Begin the exercise by pushing the pedals in a smooth, gliding motion, making sure to keep your back straight and your core engaged.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (103, 26, 3, 'As you move your legs, also push and pull the handles with your arms, alternating as you would when naturally walking or running.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (104, 26, 4, 'Continue the exercise for your set duration, remembering to breathe evenly throughout, and gradually slow your pace at the end for a cool-down period.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (105, 27, 1, 'Select the Quick Start or Manual mode on the treadmill''s control panel, then gradually increase the speed to a comfortable walking pace.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (106, 27, 2, 'Keep your back straight, your head up, and let your arms swing naturally at your sides as you walk.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (107, 27, 3, 'Pay attention to your steps, ensuring not to step too close to the front or back of the treadmill to avoid tripping or falling.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (108, 27, 4, 'To finish your workout, gradually decrease the speed until you come to a complete stop, then carefully step off the treadmill.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (109, 28, 1, 'Grab onto the handlebars, which will either be stationary (for a lower body workout) or move (for a full body workout).', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (110, 28, 2, 'Set your desired resistance and incline on the machine''s console; beginners should start with lower settings and gradually increase as their fitness improves.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (111, 28, 3, 'Begin pedaling by pushing down on one pedal; the machine''s movement should be smooth and fluid.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (112, 28, 4, 'Continue this motion for the duration of your workout, maintaining a steady pace, and ensure to keep your back straight and your core engaged throughout.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (113, 29, 1, 'Press the start button and the treadmill will begin at a slow pace, stand on the side rails while it starts moving and then step on the belt when you''re ready.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (114, 29, 2, 'Gradually increase the speed to a comfortable jogging or running pace, ensuring your movements are smooth and controlled.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (115, 29, 3, 'Maintain your posture, keeping your back straight, your arms at your sides, and looking straight ahead while you run.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (116, 29, 4, 'To finish your workout, gradually decrease the speed until you''re at a slow walk, then press the stop button and step off the treadmill once it has completely stopped moving.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (117, 30, 1, 'Set the incline level on the treadmill to a level that is challenging but manageable for you. A good starting point for beginners is an incline level of 5-10%.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (118, 30, 2, 'Press the start button on the treadmill and begin walking at a slow pace to warm up, gradually increasing your speed as your body acclimates to the incline.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (119, 30, 3, 'Maintain a proper posture while walking, keeping your back straight and your gaze forward, and avoid leaning into the incline.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (120, 30, 4, 'Continue walking for a set duration or until you''ve reached your desired distance, then gradually decrease the speed and incline to cool down before stepping off the treadmill.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (121, 31, 1, 'Stand facing the straps, grab the handles and lean back until your body is at a slight angle, keeping your feet shoulder-width apart.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (122, 31, 2, 'Keeping your body straight and your core engaged, pull your chest up to the handles by bending your elbows and squeezing your shoulder blades together.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (123, 31, 3, 'Pause at the top of the movement, then slowly lower your body back to the starting position, extending your arms fully.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (124, 31, 4, 'Repeat this movement for the desired number of repetitions, maintaining control and proper form throughout each rep.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (125, 32, 1, 'Place your opposite knee and hand on the bench for support, keeping your back flat and parallel to the floor.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (126, 32, 2, 'Let the arm holding the dumbbell hang down and a bit forward.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (127, 32, 3, 'Pull the dumbbell upward to the side of your torso, keeping your upper arm close to your side and keeping the torso stationary.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (128, 32, 4, 'Lower the dumbbell back down slowly to the starting position, completing one repetition. Repeat for the desired number of reps, then switch sides.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (129, 33, 1, 'Bend your knees slightly and lean forward from your waist until your torso is almost parallel to the floor, making sure to keep your back straight.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (130, 33, 2, 'Hold onto the bench with your free hand for support, and let the hand holding the dumbbell hang down from your shoulder.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (131, 33, 3, 'Pull the dumbbell up towards your waist, keeping your elbow close to your body and squeezing your shoulder blades together at the top of the movement.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (132, 33, 4, 'Lower the dumbbell back down in a controlled manner to the starting position, and repeat the exercise for your desired number of reps before switching to the other arm.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (133, 34, 1, 'Engage your core and lift your arms, chest, and legs off the ground, keeping your neck in a neutral position, this is your Superman pose.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (134, 34, 2, 'While maintaining this pose, pull the towel towards your chest by bending your elbows and squeezing your shoulder blades together, this is your Row.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (135, 34, 3, 'Extend your arms back out in front of you, still holding the towel, while maintaining your lifted position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (136, 34, 4, 'Lower your arms, chest, and legs back to the ground to complete one repetition, then repeat the sequence for your desired number of reps.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (137, 35, 1, 'Hold a towel with both hands at shoulder-width apart, and extend your arms fully in front of you at chest height.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (138, 35, 2, 'Keeping your back straight and your core engaged, pull the towel towards your body, bending your elbows and squeezing your shoulder blades together.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (139, 35, 3, 'Hold for a moment at the peak of the movement, then slowly extend your arms back to the starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (140, 35, 4, 'Repeat this movement for your desired number of repetitions, ensuring to maintain proper form throughout the exercise.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (141, 36, 1, 'Lie down flat on your back on the floor, with your legs extended and your feet shoulder-width apart, holding onto the towel with both hands above your head.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (142, 36, 2, 'Slowly slide your hands along the towel, pulling it towards your body while raising your torso slightly off the ground, keeping your core engaged throughout the movement.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (143, 36, 3, 'Hold this position for a few seconds, then slowly lower your torso back to the starting position, sliding your hands back up the towel.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (144, 36, 4, 'Repeat this exercise for the desired number of repetitions, ensuring to keep your movements controlled and your core engaged throughout.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (145, 37, 1, 'Slowly lower your chin towards your chest, keeping your shoulders and back still, until you feel a gentle stretch at the back of your neck.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (146, 37, 2, 'Hold this position for about 20 to 30 seconds, breathing deeply and relaxing into the stretch.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (147, 37, 3, 'Slowly lift your head back up to the starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (148, 37, 4, 'Repeat this exercise 3-5 times, ensuring to maintain a slow, controlled movement throughout.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (149, 38, 1, 'While maintaining the torso stationary (no swinging), lift the left dumbbell to the front of your body while slightly bending the elbow and palms facing down. Continue to go up until your arm is slightly above parallel to the floor. Exhale as you execute this portion of the movement and pause for a second at the top.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (150, 38, 2, 'Inhale after the second pause and slowly lower the dumbbell back down to the starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (151, 38, 3, 'Now perform the same movement for the right hand while the left hand holds the dumbbell at the waist.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (152, 38, 4, 'Continue alternating in this manner until all of the recommended repetitions for each arm have been completed.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (153, 39, 1, 'Place your hands lightly behind your head or across your chest, ensuring not to pull your neck with your hands as you perform the exercise.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (154, 39, 2, 'Slowly curl your body up towards your knees, lifting your shoulder blades off the floor and contracting your abdominal muscles.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (155, 39, 3, 'Hold this position for a moment, feeling the tension in your abdominal muscles.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (156, 39, 4, 'Slowly lower yourself back down to your starting position, keeping your abs engaged even as you return to the floor.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (157, 40, 1, 'Keep your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (158, 40, 2, 'Inhale and slowly begin to lower the dumbbells back to the starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (159, 40, 3, 'Make sure to keep your elbows close to your torso at all times.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (160, 40, 4, 'Repeat this movement for the recommended amount of repetitions.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (161, 41, 1, 'Next, extend your arms above your head, keeping the towel taut. Your palms should be facing forward.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (162, 41, 2, 'Now, pull the towel towards your forehead by bending your elbows, while keeping your upper arms stationary. Ensure your elbows are close to your head and perpendicular to the floor. This is your starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (163, 41, 3, 'Inhale and slowly lower the towel back to the starting position above your head, while keeping your arms extended and the towel taut.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (164, 41, 4, 'Exhale as you curl your arms, pulling the towel back towards your forehead. This completes one rep. Repeat the exercise for your desired number of repetitions.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (165, 42, 1, 'Place your left forearm on your left thigh, with your wrist and the dumbbell hanging over the edge of your knee, palm facing down.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (166, 42, 2, 'Slowly curl the dumbbell up by flexing your wrist, keeping your forearm pressed against your thigh for stability.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (167, 42, 3, 'Once your wrist is fully flexed, hold the position for a moment to maximize the contraction in the forearm muscles.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (168, 42, 4, 'Slowly lower the dumbbell back to the starting position, then repeat the exercise for your desired number of repetitions before switching to your right hand.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (169, 43, 1, 'Extend your arms fully in front of you at chest level, making sure the towel is taut between your hands.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (170, 43, 2, 'Slowly curl your arms towards your chest while keeping your elbows stationary, pulling the towel as if you were trying to bend it in half, this will engage your biceps.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (171, 43, 3, 'Hold this position for a few seconds to maximize muscle contraction, then slowly extend your arms back to the starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (172, 43, 4, 'Repeat this movement for the desired amount of repetitions, ensuring to keep the towel taut and your movements controlled throughout the exercise.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (173, 44, 1, 'While keeping your upper arm stationary, use your biceps to curl the weight until the dumbbells are at shoulder level. Do this while keeping your palms facing your torso.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (174, 44, 2, 'Hold the contracted position for a brief moment as you squeeze your biceps.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (175, 44, 3, 'Slowly begin to bring the dumbbells back to the starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (176, 44, 4, 'Repeat the same steps for the desired amount of repetitions and then switch arms.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (177, 45, 1, 'Rest your elbow on your thigh with your wrist just over your knee, allowing your hand to hang off the edge.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (178, 45, 2, 'Slowly lower the dumbbell as far as possible, bending your wrist and allowing it to fully extend.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (179, 45, 3, 'Curl the dumbbell back up towards the ceiling, flexing your wrist and using your forearm muscles to lift the weight.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (180, 45, 4, 'Repeat for the desired number of reps, then switch to the other arm and do the same.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (181, 46, 1, 'Place a dumbbell or any weighted object in the center of the towel and hold it securely.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (182, 46, 2, 'Keeping your elbows close to your body, slowly lift the weighted towel towards your chest by bending your elbows.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (183, 46, 3, 'Once your hands reach chest level, pause for a moment, then slowly lower the towel back down to the starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (184, 46, 4, 'Repeat this motion for your desired number of repetitions, ensuring to maintain control and proper form throughout the exercise.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (185, 47, 1, 'Position your elbow on the inside of your thigh, close to your knee, with your arm fully extended.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (186, 47, 2, 'Slowly curl the dumbbell up towards your chest, keeping your elbow stable and ensuring the movement is only happening in your forearm.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (187, 47, 3, 'Hold the position for a second, feeling the tension in your biceps.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (188, 47, 4, 'Lower the dumbbell back down to the starting position, making sure to keep the movement controlled. Repeat the exercise for your desired number of repetitions and then switch to the other arm.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (189, 48, 1, 'Bend your knees and lift both legs off the floor, then loop the towel under your feet, holding one end of the towel in each hand.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (190, 48, 2, 'Keep your elbows close to your body and pull the towel towards your chest, curling your legs up as you do so, similar to a hammer curl with your legs.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (191, 48, 3, 'Pause for a moment at the top of the movement, then slowly lower your legs back down to the starting position, keeping tension in the towel.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (192, 48, 4, 'Repeat this exercise for the desired number of repetitions, ensuring to maintain proper form throughout.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (193, 49, 1, 'Sit down on the floor between the chairs and place your hands on the seat edges, fingers pointing towards your feet, and bend your knees so that your feet are flat on the floor.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (194, 49, 2, 'Push down on the chairs and lift your body off the ground, keeping your elbows bent and your shoulders down, away from your ears.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (195, 49, 3, 'Slowly lower your body by bending your elbows until your upper arms are parallel to the floor, keeping your back straight and your core engaged.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (196, 49, 4, 'Push yourself back up to the starting position by straightening your arms, ensuring to keep your body straight and your core engaged throughout the movement. Repeat this exercise for the desired number of repetitions.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (197, 50, 1, 'Extend your right arm straight out in front of you at shoulder height, keeping your palm facing down.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (198, 50, 2, 'Gently pull your right arm across your body using your left hand, applying light pressure until you feel a stretch in your shoulder.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (199, 50, 3, 'Hold this position for about 20 to 30 seconds, making sure to breathe deeply throughout the stretch.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (200, 50, 4, 'Release the stretch and repeat the same steps on the other side with your left arm.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (201, 51, 1, 'Next, raise your legs parallel to the ground into an L-shape, keeping your legs straight and together; this is your starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (202, 51, 2, 'Using your upper body strength, pull yourself up until your chin is above the bar, while maintaining the L-shape with your legs.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (203, 51, 3, 'Hold this position for a moment, ensuring your core is engaged and your body is in a straight line.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (204, 51, 4, 'Finally, lower yourself back down in a controlled manner to the starting position, keeping your legs in the L-shape throughout the exercise.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (205, 52, 1, 'With your palms facing away from your body, reach up and grab the bar with a wide grip, keeping your arms fully extended.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (206, 52, 2, 'Next, engage your core and lift your hips off the ground, pulling your body upwards towards the bar in an inverted position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (207, 52, 3, 'As you reach the top of the movement, use your arms to assist in pulling your body up and over the bar, while keeping your legs straight and together.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (208, 52, 4, 'Slowly lower yourself back down to the starting position, maintaining control throughout the movement to ensure that you''re using your muscles rather than momentum.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (209, 53, 1, 'Pull your body up by driving your elbows towards the floor, keep pulling until your chin is above the bar, while keeping your body straight and core engaged.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (210, 53, 2, 'At the top of the movement, pause for a second, then slowly lower your body back down to the starting position, maintaining control throughout the descent.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (211, 53, 3, 'Ensure your arms are fully extended before starting the next repetition.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (212, 53, 4, 'Repeat the process for the desired number of repetitions, making sure to maintain proper form throughout.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (213, 54, 1, 'Reach up and grip the bar with one hand closer to you and the other further away, in an overhand grip. Your hands should be shoulder-width apart, forming a line across your body.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (214, 54, 2, 'Pull your body up towards the bar while twisting your torso towards the hand that is closer to you. Your aim is to touch your shoulder to the bar.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (215, 54, 3, 'Lower your body back down to the starting position in a controlled manner, ensuring to keep your body straight and not to swing.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (216, 54, 4, 'Repeat the exercise on the other side by switching your hand positions and twisting your torso in the opposite direction.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (217, 55, 1, 'Stand between the chairs and grip the backs or the seats of the chairs with each hand, ensuring your grip is firm and secure.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (218, 55, 2, 'Slowly lift your body off the ground by pulling up with your arms and shoulders, bending your knees at a 90-degree angle as you rise.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (219, 55, 3, 'Hold this position for a few seconds, feeling the tension in your upper body and core muscles.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (220, 55, 4, 'Gradually lower your body back down to the starting position, keeping your knees bent, then repeat the exercise for the desired number of repetitions.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (221, 56, 1, 'Pull your shoulder blades down and back, bend your legs at the knees if necessary, and cross your ankles behind you.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (222, 56, 2, 'Engage your core and pull yourself up until your chin is above the bar, maintaining control and not using momentum to swing your body up.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (223, 56, 3, 'Hold the position at the top for a moment, ensuring your chest is close to the bar and your shoulder blades are fully retracted.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (224, 56, 4, 'Slowly lower yourself back down to the starting position, fully extending your arms while maintaining control of your movement.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (225, 57, 1, 'With a firm grip on the bar, pull your shoulder blades down and back, bend your legs at the knees if necessary, and cross your ankles.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (226, 57, 2, 'Engage your core and pull your body up until your chin is above the bar while keeping your elbows close to your body.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (227, 57, 3, 'Hold this position for a moment, ensuring your chest is close or touching the bar.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (228, 57, 4, 'Slowly lower your body back down to the starting position, fully extending your arms and maintaining control throughout the movement.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (229, 58, 1, 'Lift your hips up towards the ceiling, straightening your legs and pushing your heels down towards the floor to form an inverted V shape with your body.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (230, 58, 2, 'Spread your fingers wide on the mat and press down through your palms, keeping your head between your arms and looking towards your knees.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (231, 58, 3, 'Make sure your back is flat, and your weight is evenly distributed between your hands and feet.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (232, 58, 4, 'Hold this position for a few breaths, then gently lower your body back to the starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (233, 59, 1, 'Extend your right arm out in front of you, with your palm facing down.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (234, 59, 2, 'With your left hand, gently grasp the fingers of your extended right hand.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (235, 59, 3, 'Slowly pull the fingers of your right hand towards your body until you feel a stretch along the top of your wrist and forearm.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (236, 59, 4, 'Hold this stretch for about 15 to 30 seconds, then release and switch to the other hand. Repeat this process for both hands as needed.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (237, 60, 1, 'Bend forward at the waist so your chest is leaning forward over your feet. Keep your back straight and let your arms hang straight down, palms facing each other.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (238, 60, 2, 'Keep a slight bend in your elbows and raise your arms out to the sides until they''re at shoulder level, like you''re spreading your wings. This is the fly part of the exercise.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (239, 60, 3, 'Pause for a moment at the top of the movement, then slowly lower the dumbbells back to the starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (240, 60, 4, 'Repeat this movement for your desired number of repetitions, remembering to keep your core engaged and back straight throughout the exercise.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (241, 61, 1, 'Bend your knees, bring the soles of your feet together, and draw your heels as close to your body as you can, forming a diamond shape with your legs.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (242, 61, 2, 'Hold onto your feet or ankles, keeping your elbows slightly bent and directed towards your knees.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (243, 61, 3, 'Inhale deeply, and as you exhale, press your knees down towards the floor, trying to make them touch the ground; this will stretch your inner thighs and hips.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (244, 61, 4, 'Hold this pose for 3-5 breaths, or as long as comfortable, then gently release your legs and return to the starting position.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (245, 62, 1, 'Push your body up onto your forearms and toes, making sure your elbows are directly under your shoulders and your forearms are facing forward.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (246, 62, 2, 'Keep your body in a straight line from your head to your feet, ensuring your back is flat and your hips are not dropping or rising.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (247, 62, 3, 'Engage your core muscles and hold this position for as long as you can, ideally aiming for 30 seconds to 1 minute.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (248, 62, 4, 'Lower your body back to the starting position in a controlled manner and repeat the exercise as desired.', NULL);
INSERT INTO exercise_instruction (id, exercise_id, step_number, instruction_text, instruction_text_de) VALUES (249, 63, 1, 'Align your upper thighs or hips with the larger pad, allowing your torso to bend forward from the waist and hang down.', NULL);
